+{
+  "name": "cbt_backward_tab",
+  "description": "CBT (CSI Z) moves cursor backward to the previous tab stop",
+  "initial_size": [80, 24],
+  "input_bytes_hex": "1b5b323047411b5b5a42",
+  "comment": "CHA(20) → col 19, print A at col 19 (cursor → 20), CSI Z back-tab → col 16, print B at col 16",
+  "expected": {
+    "cursor": { "row": 0, "col": 17 },
+    "cells": [
+      { "row": 0, "col": 19, "char": "A" },
+      { "row": 0, "col": 16, "char": "B" }
+    ]
+  }
+}

